function parseCSV(raw) {
  if (!raw || !String(raw).trim()) return [];
  const text = String(raw).replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  const rows = [];
  let row = [];
  let field = '';
  let i = 0;
  let inQuotes = false;

  while (i < text.length) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') { field += '"'; i += 2; continue; }
        inQuotes = false; i += 1; continue;
      }
      field += ch; i += 1; continue;
    }
    if (ch === '"') { inQuotes = true; i += 1; continue; }
    if (ch === ',') { row.push(field); field = ''; i += 1; continue; }
    if (ch === '\n') { row.push(field); field = ''; rows.push(row); row = []; i += 1; continue; }
    field += ch; i += 1;
  }
  row.push(field);
  if (row.length > 1 || row[0] !== '') rows.push(row);
  if (!rows.length) return [];
  const header = rows[0].map((h) => String(h || '').trim());
  return rows.slice(1)
    .filter((r) => r.some((v) => String(v || '').trim() !== ''))
    .map((r) => { const obj = {}; header.forEach((h, idx) => { obj[h] = r[idx] ?? ''; }); return obj; });
}

// Fetch CT Inventory uses Table=Inventory (one row per bottle, already in-stock only)
// Fetch CT Notes uses Table=Notes (tasting notes per wine)
const inventoryResult = $('Fetch CT Inventory').first()?.json || {};
const notesResult = $('Fetch CT Notes').first()?.json || {};

if (inventoryResult.status && inventoryResult.status !== 'success') {
  throw new Error(inventoryResult.message || 'CellarTracker inventory export failed');
}
if (notesResult.status && notesResult.status !== 'success') {
  throw new Error(notesResult.message || 'CellarTracker notes export failed');
}

const inventoryRaw = inventoryResult.data || '';
const notesRaw = notesResult.data || '';
if (!String(inventoryRaw).trim()) throw new Error('Inventory CSV input is empty');

const inventory = parseCSV(inventoryRaw);
const notes = parseCSV(notesRaw);

// Build notes lookup by iWine
const notesByWine = {};
for (const n of notes) {
  const id = String(n.iWine || n.iwine || '').trim();
  if (!id) continue;
  if (!notesByWine[id]) notesByWine[id] = { texts: [], latestDate: null };
  const noteText = String(n.Note || '').trim();
  if (noteText) notesByWine[id].texts.push(noteText);
  const dateText = String(n.Date || '').trim();
  if (dateText) {
    const d = new Date(dateText);
    if (!Number.isNaN(d.getTime())) {
      const cur = notesByWine[id].latestDate ? new Date(notesByWine[id].latestDate) : null;
      if (!cur || d > cur) notesByWine[id].latestDate = dateText;
    }
  }
}

const toInt = (v) => { if (v === '' || v == null) return null; const n = parseInt(v, 10); return Number.isFinite(n) ? n : null; };
const toFloat = (v) => { if (v === '' || v == null) return null; const n = parseFloat(String(v).replace(/[^0-9.-]/g, '')); return Number.isFinite(n) ? n : null; };
const toStr = (v) => { if (v === '' || v == null) return null; const s = String(v).trim(); return s === '' ? null : s; };
const toDate = (v) => {
  const s = toStr(v); if (!s) return null;
  // M/D/YYYY format from CT
  const mdy = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (mdy) return `${mdy[3]}-${String(mdy[1]).padStart(2,'0')}-${String(mdy[2]).padStart(2,'0')}`;
  const d = new Date(s); return Number.isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10);
};

const output = [];

for (const row of inventory) {
  // Inventory export: one row per unique bottle position (already in-stock)
  const ct_barcode = toStr(row.Barcode);
  const ct_iwine = toInt(row.iWine);
  if (!ct_barcode || !ct_iwine) continue;

  const noteData = notesByWine[String(ct_iwine)] || { texts: [], latestDate: null };
  const my_notes = noteData.texts.length ? noteData.texts.join(' | ') : null;

  // Inventory column names differ from Bottles export:
  //   Price (not BottleCost), Currency (not BottleCostCurrency), StoreName (not Store), Size (not BottleSize)
  const bottle_cost = toFloat(row.Price);
  const bottle_cost_currency = toStr(row.Currency);
  const store = toStr(row.StoreName);
  const bottle_size = toStr(row.Size);

  const embeddingParts = [
    toStr(row.Wine),
    toInt(row.Vintage) ? `Vintage ${row.Vintage}` : null,
    toStr(row.Producer),
    toStr(row.Type),
    toStr(row.Varietal),
    toStr(row.Appellation),
    toStr(row.Region),
    toStr(row.Country),
    my_notes ? `Tasting notes: ${my_notes}` : null,
  ].filter(Boolean);

  // Store full row as JSONB — preserves Valuation, WA/WS/CT scores, community data, etc.
  const raw_ct_row = {};
  for (const [k, v] of Object.entries(row)) { if (v !== '') raw_ct_row[k] = v; }

  output.push({
    json: {
      ct_barcode,
      ct_iwine,
      bottle_state: '1',
      wine: toStr(row.Wine),
      vintage: toInt(row.Vintage),
      producer: toStr(row.Producer),
      wine_type: toStr(row.Type),
      color: toStr(row.Color),
      varietal: toStr(row.Varietal),
      master_varietal: toStr(row.MasterVarietal),
      designation: toStr(row.Designation),
      vineyard: toStr(row.Vineyard),
      appellation: toStr(row.Appellation),
      region: toStr(row.Region),
      sub_region: toStr(row.SubRegion),
      country: toStr(row.Country),
      locale: toStr(row.Locale),
      bottle_size,
      drink_from: toInt(row.BeginConsume),
      drink_to: toInt(row.EndConsume),
      my_notes,
      note_date: noteData.latestDate ? toDate(noteData.latestDate) : null,
      location: toStr(row.Location),
      bin: toStr(row.Bin),
      store,
      purchase_date: toDate(row.PurchaseDate),
      delivery_date: null,
      bottle_cost,
      bottle_cost_currency,
      bottle_note: toStr(row.BottleNote),
      purchase_note: null,
      consumption_date: null,
      consumption_type: null,
      consumption_note: null,
      consumption_revenue: null,
      consumption_revenue_currency: null,
      removed_at: null,
      last_synced_at: new Date().toISOString(),
      raw_ct_row,
      embedding_text: embeddingParts.join('. '),
    },
  });
}

if (!output.length) throw new Error('Parsed zero bottles from CellarTracker inventory export');
return output;

const items = $input.all();
const activeBarcodes = Array.from(new Set(items.map(i => i.json.ct_barcode).filter(Boolean)));
return [{ json: { active_barcodes: activeBarcodes, count: activeBarcodes.length } }];

const current = new Set($('Collect Active Barcodes').first().json.active_barcodes || []);
const dbRows = $input.all().map(i => i.json || {});
const dbAll = new Set();
const dbActive = new Set();
const dbRemoved = new Set();
for (const row of dbRows) {
  const barcode = row.ct_barcode;
  if (!barcode) continue;
  dbAll.add(barcode);
  if (row.removed_at == null) dbActive.add(barcode);
  else dbRemoved.add(barcode);
}
const added = [];
const restored = [];
const unchanged = [];
for (const barcode of current) {
  if (dbRemoved.has(barcode)) restored.push(barcode);
  else if (dbActive.has(barcode)) unchanged.push(barcode);
  else added.push(barcode);
}
const removed = [];
for (const barcode of dbActive) {
  if (!current.has(barcode)) removed.push(barcode);
}
return [{ json: {
  added_barcodes: added,
  restored_barcodes: restored,
  removed_barcodes: removed,
  unchanged_barcodes: unchanged,
  added_count: added.length,
  restored_count: restored.length,
  removed_count: removed.length,
  unchanged_count: unchanged.length,
  current_count: current.size,
  db_active_count: dbActive.size
} }];

const items = $('Parse CSV + Merge Notes').all();
if (!items.length) return [];

const byWine = new Map();

for (const item of items) {
  const row = item.json;
  if (!row.ct_iwine) continue;

  if (!byWine.has(row.ct_iwine)) {
    byWine.set(row.ct_iwine, {
      ct_iwine: row.ct_iwine,
      wine: row.wine,
      vintage: row.vintage,
      producer: row.producer,
      wine_type: row.wine_type,
      color: row.color,
      varietal: row.varietal,
      master_varietal: row.master_varietal,
      designation: row.designation,
      vineyard: row.vineyard,
      appellation: row.appellation,
      region: row.region,
      sub_region: row.sub_region,
      country: row.country,
      locale: row.locale,
      bottle_size: row.bottle_size,
      drink_from: row.drink_from,
      drink_to: row.drink_to,
      my_notes: row.my_notes,
      note_date: row.note_date,
      embedding_text: row.embedding_text || '',
    });
  }
}

const source_items = Array.from(byWine.values());

if (!source_items.length) {
  throw new Error('No wine rows available for embedding');
}

return [{
  json: {
    batch_count: source_items.length,
    source_items,
    request_body: {
      model: 'openai/text-embedding-3-small',
      input: source_items.map(i => i.embedding_text || ''),
    },
  },
}];

const resp = $json;
const prep = $('Build Wine Embedding Batch Request').first().json;
const sourceItems = prep.source_items || [];
const data = Array.isArray(resp.data) ? resp.data : [];
if (data.length !== sourceItems.length) {
  throw new Error(`Embedding count mismatch. Expected ${sourceItems.length}, got ${data.length}`);
}
return sourceItems.map((wine, idx) => {
  const embedding = data[idx]?.embedding;
  if (!Array.isArray(embedding)) throw new Error(`Missing embedding for batch index ${idx}`);
  return { json: { ...wine, embedding: '[' + embedding.join(',') + ']' } };
});

const wineCount = $('Build Wines Upsert Payload').first().json.count || 0;
const bottleCount = $('Build Bottles Upsert Payload').first().json.count || 0;
const diff = $('Compute Inventory Diff').first().json;
const softDelete = $('Soft-Delete Removed Bottles by Barcode').first().json || {};
const prefResult = $('Infer Preferences from Purchases').first().json || {};
const removedApplied = softDelete.soft_deleted ?? softDelete.removed_count ?? diff.removed_count ?? 0;
const preferenceUpserts = prefResult.preference_upserts ?? 0;
const today = new Date().toISOString().slice(0, 10);
const summary = 'Wine inventory sync ' + today + ': ' + wineCount + ' wines and ' + bottleCount + ' bottles processed from CellarTracker. Added=' + (diff.added_count || 0) + ', restored=' + (diff.restored_count || 0) + ', removed=' + (diff.removed_count || 0) + ', unchanged=' + (diff.unchanged_count || 0) + '. Soft-deleted=' + removedApplied + '. Preference upserts=' + preferenceUpserts + '.';
return [{ json: { summary, wine_count: wineCount, bottle_count: bottleCount, ...diff, soft_deleted: removedApplied, preference_upserts: preferenceUpserts } }];
